# ---------------------------------------------------------------------------
# Tests for validate_email
# ---------------------------------------------------------------------------
class TestValidateEmail:
    """Tests for the validate_email function."""

    # ---- Normal / valid cases ----
    @pytest.mark.parametrize("email", [
        "user@example.com",
        "john.doe@company.org",
        "a@b.co",
        "first.last@sub.domain.com",
        "user+tag@example.com",
        "user_name@example.co.uk",
        "123@456.789",
    ])
    def test_valid_emails_return_true(self, email):
        assert validate_email(email) is True

    # ---- Invalid: missing '@' ----
    @pytest.mark.parametrize("email", [
        "plainaddress",
        "no-at-sign.com",
        "user.example.com",
    ])
    def test_email_without_at_symbol(self, email):
        assert validate_email(email) is False

    # ---- Invalid: multiple '@' symbols ----
    @pytest.mark.parametrize("email", [
        "user@@example.com",
        "a@b@c.com",
        "user@name@domain.com",
    ])
    def test_email_with_multiple_at_symbols(self, email):
        assert validate_email(email) is False

    # ---- Invalid: empty local or domain ----
    def test_empty_local_part(self):
        assert validate_email("@example.com") is False

    def test_empty_domain_part(self):
        assert validate_email("user@") is False

    def test_only_at_symbol(self):
        assert validate_email("@") is False

    # ---- Invalid: domain without a dot ----
    @pytest.mark.parametrize("email", [
        "user@localhost",
        "user@domain",
        "test@nope",
    ])
    def test_domain_without_dot(self, email):
        assert validate_email(email) is False

    # ---- Edge cases: falsy / empty inputs ----
    def test_empty_string(self):
        assert validate_email("") is False

    def test_none_input(self):
        assert validate_email(None) is False

    # ---- Edge cases: unusual-but-accepted-by-this-validator inputs ----
    def test_dot_in_local_part_only_still_valid(self):
        # Function only requires a dot in the domain.
        assert validate_email("a.b@c.d") is True

    def test_whitespace_email_has_no_at(self):
        assert validate_email("   ") is False


# ---------------------------------------------------------------------------
# Tests for calculate_area
# ---------------------------------------------------------------------------
class TestCalculateArea:
    """Tests for the calculate_area function."""

    # ---- Rectangle ----
    def test_rectangle_area_basic(self):
        assert calculate_area("rectangle", width=4, height=5) == 20

    def test_rectangle_area_floats(self):
        assert calculate_area("rectangle", width=2.5, height=4.0) == pytest.approx(10.0)

    def test_rectangle_area_zero(self):
        assert calculate_area("rectangle", width=0, height=5) == 0

    def test_rectangle_is_square_when_equal_sides(self):
        assert calculate_area("rectangle", width=3, height=3) == 9

    def test_rectangle_missing_kwargs_raises_keyerror(self):
        with pytest.raises(KeyError):
            calculate_area("rectangle", width=4)  # missing height
        with pytest.raises(KeyError):
            calculate_area("rectangle")  # missing both

    # ---- Circle ----
    def test_circle_area_basic(self):
        assert calculate_area("circle", radius=1) == pytest.approx(math.pi)

    def test_circle_area_larger_radius(self):
        assert calculate_area("circle", radius=5) == pytest.approx(math.pi * 25)

    def test_circle_area_float_radius(self):
        assert calculate_area("circle", radius=2.5) == pytest.approx(math.pi * 6.25)

    def test_circle_area_zero_radius(self):
        assert calculate_area("circle", radius=0) == 0

    def test_circle_missing_radius_raises_keyerror(self):
        with pytest.raises(KeyError):
            calculate_area("circle")

    # ---- Triangle ----
    def test_triangle_area_basic(self):
        assert calculate_area("triangle", base=10, height=4) == 20.0

    def test_triangle_area_float(self):
        assert calculate_area("triangle", base=3.5, height=2.0) == pytest.approx(3.5)

    def test_triangle_area_zero_base(self):
        assert calculate_area("triangle", base=0, height=5) == 0

    def test_triangle_missing_kwargs_raises_keyerror(self):
        with pytest.raises(KeyError):
            calculate_area("triangle", base=10)  # missing height
        with pytest.raises(KeyError):
            calculate_area("triangle", height=5)  # missing base

    # ---- Unknown shape ----
    @pytest.mark.parametrize("shape", [
        "pentagon",
        "hexagon",
        "sphere",
        "",
        "Rectangle",   # case-sensitive: capital R is not accepted
        "CIRCLE",
    ])
    def test_unknown_shape_raises_valueerror(self, shape):
        with pytest.raises(ValueError, match="Unknown shape"):
            calculate_area(shape, width=1, height=1, radius=1, base=1)

    def test_unknown_shape_error_message_contains_shape_name(self):
        with pytest.raises(ValueError) as exc_info:
            calculate_area("octagon", side=5)
        assert "octagon" in str(exc_info.value)

    # ---- Negative values: function does not validate, but results are computable ----
    def test_rectangle_negative_dimensions_returns_product(self):
        # Documenting current behavior: no validation against negatives.
        assert calculate_area("rectangle", width=-4, height=5) == -20

    def test_circle_negative_radius_is_squared_to_positive(self):
        assert calculate_area("circle", radius=-3) == pytest.approx(math.pi * 9)

    def test_triangle_negative_base(self):
        assert calculate_area("triangle", base=-10, height=4) == -20.0

    # ---- Extra kwargs are ignored ----
    def test_extra_kwargs_are_ignored(self):
        assert calculate_area("rectangle", width=2, height=3, radius=100) == 6
